"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[20077],{35709:e=>{e.exports=JSON.parse('{"tag":{"label":"sanity","permalink":"/dst-api-webdocs/docs/tags/sanity","allTagsPath":"/dst-api-webdocs/docs/tags","count":57,"items":[{"id":"game-scripts/prefabs/alterguardian_phase4_lunarrift","title":"Alterguardian Phase4 Lunarrift","description":"Manages the behavior, state transitions, combat mechanics, and environment interactions of the Phase 4 Lunar Rift boss in DST\'s Wagstaff finale.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/alterguardian_phase4_lunarrift"},{"id":"game-scripts/prefabs/armor_dreadstone","title":"Armor Dreadstone","description":"A high-defense body armor piece that regenerates condition during Insanity Mode and synergizes with the Dreadstone set.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_dreadstone"},{"id":"game-scripts/prefabs/armor_sanity","title":"Armor Sanity","description":"Provides protective armor and applies a sanity penalty to the wearer when damage is blocked.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_sanity"},{"id":"game-scripts/prefabs/armor_voidcloth","title":"Armor Voidcloth","description":"A wearable item that grants shadow-aligned resistance, planar defense, and sets a negative sanity aura when equipped.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_voidcloth"},{"id":"game-scripts/prefabs/atrium_overgrowth","title":"Atrium Overgrowth","description":"A static environmental prop that displays incremental lore lines when examined by players wearing ancient_reader gear, while granting a large sanity aura penalty and saving/loading story progression state.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/atrium_overgrowth"},{"id":"game-scripts/prefabs/balloonparty","title":"Balloonparty","description":"A party-themed decorative balloon that grants nearby players periodic sanity recovery when active in the world, with associated confetti effects and a debuff buff that scales with party size.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/balloonparty"},{"id":"game-scripts/prefabs/bandage_butterflywings","title":"Bandage Butterflywings","description":"A consumable item that restores health and sanity when used, requiring the \\"walter_camp_firstaid\\" skill to trigger the sanity bonus.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bandage_butterflywings"},{"id":"game-scripts/prefabs/batbat","title":"Batbat","description":"A consumable weapon item that deals damage on attack and drains health/sanity from valid targets on critical hits.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/batbat"},{"id":"game-scripts/prefabs/bernie_common","title":"Bernie Common","description":"Provides utility functions to determine when Bernie the Yeti becomes aggressive based on Willow\'s sanity and skill choices.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bernie_common"},{"id":"game-scripts/brains/berniebrain","title":"Berniebrain","description":"Manages the AI behavior of Bernie the Big Bernie, including detecting when to transform, finding a leader to follow, taunting nearby sanity monsters, and switching between wandering and following states.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/berniebrain"},{"id":"game-scripts/components/book","title":"Book","description":"Manages interactive reading and perusing behavior for books, including sanity effects, use consumption, and optional visual FX.","permalink":"/dst-api-webdocs/docs/game-scripts/components/book"},{"id":"game-scripts/components/brightmarespawner","title":"Brightmarespawner","description":"Tracks players in Lunacy Mode and periodically spawns Brightmare Gestalt entities based on player sanity levels and population rules.","permalink":"/dst-api-webdocs/docs/game-scripts/components/brightmarespawner"},{"id":"game-scripts/prefabs/bunnyman","title":"Bunnyman","description":"A sentient pig-like creature that can follow players, wear hats, and enter a powerful \\"beard lord\\" nightmare state under certain conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bunnyman"},{"id":"game-scripts/components/coach","title":"Coach","description":"Provides periodic support effects (sanity and fight buffs) to nearby players and followers when the host entity is tagged as \\"coaching\\".","permalink":"/dst-api-webdocs/docs/game-scripts/components/coach"},{"id":"game-scripts/prefabs/cutlichen","title":"Cutlichen","description":"A consumable food item that restores health and hunger but reduces sanity, and spoils over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cutlichen"},{"id":"game-scripts/prefabs/decor_flowervase","title":"Decor Flowervase","description":"A decorative container component that holds and displays flowers, providing light, sanity effects, and inventory interactions when properly equipped.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/decor_flowervase"},{"id":"game-scripts/prefabs/deerclops_eyeball","title":"Deerclops Eyeball","description":"A consumable boss loot item dropped by Deerclops that restores health, hunger, and sanity when eaten.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/deerclops_eyeball"},{"id":"game-scripts/prefabs/driedplants_defs","title":"Driedplants Defs","description":"Defines data for dried plant items, including healing/sanity values and spawn configurations for eating effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/driedplants_defs"},{"id":"game-scripts/components/firebug","title":"Firebug","description":"Triggers periodic announcements and spawns a prefab when an entity\'s fire timer expires, optionally subject to sanity thresholds.","permalink":"/dst-api-webdocs/docs/game-scripts/components/firebug"},{"id":"game-scripts/prefabs/flower","title":"Flower","description":"Represents a customizable plant entity that can transform into a rose under certain conditions and interacts with sanity, combat, and world state systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/flower"},{"id":"game-scripts/prefabs/flower_evil","title":"Flower Evil","description":"A harvestable, sanity-affecting decorative flower that drops petals upon picking and can ignite wildfires.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/flower_evil"},{"id":"game-scripts/prefabs/forgetmelots","title":"Forgetmelots","description":"A consumable vegetarian item that provides minimal sanity restoration, spoils quickly, and can be dried; also serves as a cat toy and vase decoration.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/forgetmelots"},{"id":"game-scripts/prefabs/halloweenpotion_buffs","title":"Halloweenpotion Buffs","description":"Creates and manages buff entities that apply periodic health/sanity restoration or bravery effects when attached via the halloween potion items.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/halloweenpotion_buffs"},{"id":"game-scripts/components/hallucinations","title":"Hallucinations","description":"Manages the spawning and tracking of hallucination entities based on player sanity, time of day, and environment lighting.","permalink":"/dst-api-webdocs/docs/game-scripts/components/hallucinations"},{"id":"game-scripts/prefabs/hermitcrabtea_defs","title":"Hermitcrabtea Defs","description":"Defines tea ingredients and their associated buffs for the Hermit Crab Teapot prefab.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermitcrabtea_defs"},{"id":"game-scripts/components/itemaffinity","title":"Itemaffinity","description":"Manages a priority-based sanity bonus for characters based on specific items carried in inventory.","permalink":"/dst-api-webdocs/docs/game-scripts/components/itemaffinity"},{"id":"game-scripts/prefabs/minotaurhorn","title":"Minotaurhorn","description":"A consumable meat item that restores health, hunger, and reduces sanity when eaten.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/minotaurhorn"},{"id":"game-scripts/prefabs/moonbutterflywings","title":"Moonbutterflywings","description":"A consumable inventory item that restores health, hunger, and sanity when eaten, but spoils quickly.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moonbutterflywings"},{"id":"game-scripts/prefabs/nightlight","title":"Nightlight","description":"A deployable structure that provides shadow-light illumination and sanity benefits while consuming nightmare fuel.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightlight"},{"id":"game-scripts/prefabs/nightmaregrowth","title":"Nightmaregrowth","description":"A spawner-like entity that triggers the growth of a nightmare growth prefab, which emits strong negative sanity aura and can destroy nearby structures.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightmaregrowth"},{"id":"game-scripts/prefabs/nightmarerock","title":"Nightmarerock","description":"A reactive environmental obstacle that physically rises or lowers based on nearby player sanity status, used in the sanity rock mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightmarerock"},{"id":"game-scripts/prefabs/oceanshadowcreature","title":"Oceanshadowcreature","description":"A highly specialized entity component for the Ocean Horror (Shadow Creature) that manages boat attachment, sanity-based targeting, teleportation logic, and network-aware transparency and ripple effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanshadowcreature"},{"id":"game-scripts/prefabs/petals_evil","title":"Petals Evil","description":"A perishable, dryable, and consumable item that grants sanity loss; used as a crafting component or food source with negative effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/petals_evil"},{"id":"game-scripts/prefabs/rabbitkingspear","title":"Rabbitkingspear","description":"A usable weapon item that grants sanity restoration against manrabbit targets and degrades after repeated use.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rabbitkingspear"},{"id":"game-scripts/components/reader","title":"Reader","description":"Enables an entity to read books and track bookworm status and sanity penalties.","permalink":"/dst-api-webdocs/docs/game-scripts/components/reader"},{"id":"game-scripts/prefabs/royal_jelly","title":"Royal Jelly","description":"A consumable food item that restores health, hunger, and sanity; has a moderate perish time and can be stacked.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/royal_jelly"},{"id":"game-scripts/components/sanity","title":"Sanity","description":"Manages sanity value, mode (Insanity/Lunacy), and related mechanics for an entity, including dynamic rate calculation from environmental and aura sources.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sanity"},{"id":"game-scripts/components/sanity_replica","title":"Sanity Replica","description":"Network-replicated component that synchronizes sanity state, mode, and related properties between server and client for player entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sanity_replica"},{"id":"game-scripts/map/static_layouts/sanity_wormhole_1","title":"Sanity Wormhole 1","description":"Defines a static 16x16 tilemap layout containing sanity rocks and a central wormhole object for use in world generation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/sanity_wormhole_1"},{"id":"game-scripts/components/sanityaura","title":"Sanityaura","description":"Computes and provides sanity-affecting aura values for an entity within a defined radius.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sanityaura"},{"id":"game-scripts/components/sanityauraadjuster","title":"Sanityauraadjuster","description":"Manages periodic adjustment of sanity aura effects by running a custom callback function on a timer.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sanityauraadjuster"},{"id":"game-scripts/prefabs/shadow_leech","title":"Shadow Leech","description":"A hostile shadow creature prefab that spawns in response to the Daywalker, tracks it via EntityTracker, and applies a sanity aura based on observer perception.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadow_leech"},{"id":"game-scripts/prefabs/shadowchanneler","title":"Shadowchanneler","description":"A non-tangible boss-phase entity that spawns shadow minions and manages their behavior through a commander system, with dynamic sanity aura and transparency.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadowchanneler"},{"id":"game-scripts/prefabs/shadowcreature","title":"Shadowcreature","description":"Spawns shadow creatures that attack sane players and drain sanity when targets are nearby.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadowcreature"},{"id":"game-scripts/components/shadowcreaturespawner","title":"Shadowcreaturespawner","description":"Manages the spawning, tracking, and population control of shadow creatures (e.g., Crawling Horrors, Ocean Horrors, Terrorbeaks) for players based on sanity levels and game mode.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shadowcreaturespawner"},{"id":"game-scripts/prefabs/shadowheart","title":"Shadowheart","description":"An inventory item that emits periodic sound and animation cues when dropped, and halts these behaviors when held by a player.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadowheart"},{"id":"game-scripts/prefabs/shadowheart_infused","title":"Shadowheart Infused","description":"A consumable item that provides a temporary sanity boost and emits a moderate sanity aura while held or carried.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadowheart_infused"},{"id":"game-scripts/components/staffsanity","title":"Staffsanity","description":"Modifies the rate of sanity change when used as a staff-like item to cast abilities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/staffsanity"},{"id":"game-scripts/components/transparentonsanity","title":"Transparentonsanity","description":"Adjusts an entity\'s transparency and sound volume based on the player\'s sanity and combat state, with optional custom logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/transparentonsanity"},{"id":"game-scripts/prefabs/vaultrelic","title":"Vaultrelic","description":"A collectible decorative item that can be placed on furniture, decorated with flowers, and repaired; it provides ambient light and sanity benefits when freshly decorated.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vaultrelic"},{"id":"game-scripts/brains/waveyjoneshandbrain","title":"Waveyjoneshandbrain","description":"Controls the behavior of Wavey Jones\' hand entity by selecting and performing repair-related actions on boat components based on current conditions and player sanity.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/waveyjoneshandbrain"},{"id":"game-scripts/prefabs/waxwell","title":"Waxwell","description":"Defines the Waxwell character prefab, a magician-specialized player with shadow-minion management, sanity penalties, and shadow-level equipment announcements.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waxwell"},{"id":"game-scripts/prefabs/wendy","title":"Wendy","description":"Implements Wendy\u2019s unique gameplay mechanics, including Abigail the ghostly friend, sanity aura adjustments during Sisturn events, and bonding progression.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wendy"},{"id":"game-scripts/prefabs/wickerbottom","title":"Wickerbottom","description":"Implements Wickerbottom\'s unique gameplay mechanics, including the ability to spawn shadow creatures from reading books while insane, refusal of spoiled food, and bonus book-related interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wickerbottom"},{"id":"game-scripts/prefabs/wintersfeastbuff","title":"Wintersfeastbuff","description":"Applies a timed damage-healing buff that restores health, hunger, and sanity over time while reducing hunger burn rate, and supports bonus duration extension based on feast statistics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wintersfeastbuff"},{"id":"game-scripts/prefabs/wormwood","title":"Wormwood","description":"Manages the bloom-based progression system for the Wormwood character, including sanity regulation from nearby plants, pet leadership, and photosynthesis-based health regeneration.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wormwood"},{"id":"game-scripts/prefabs/wortox","title":"Wortox","description":"Manages Wortox\'s soul-based gameplay systems, including soul collection, storage, overloading, portal hopping, and skill-triggered buffs and effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wortox"}],"unlisted":false}}')}}]);